(window.webpackJsonp=window.webpackJsonp||[]).push([[59],{686:function(n,r){n.exports="\x3c!-- \r\ntitle: Nginx\r\nsort: \r\n--\x3e \r\n\r\n# Nginx入门\r\n\r\n> [OpenResty](http://openresty.org/cn/)\r\n\r\n## 安装\r\n\r\n```yml\r\n# docker-compose\r\nversion: '3.1'\r\nservices:\r\n  nginx:\r\n    restart: always\r\n    image: nginx\r\n    container_name: nginx\r\n    ports:\r\n      - 80:80\r\n    volumes: \r\n      - /opt/docker_nginx/conf.d:/etc/nginx/conf.d\r\n      - /usr/share/nginx/html\r\n```\r\n\r\n## 默认\r\n\r\n```nginx\r\n# /etc/nginx/sites-enable/default\r\n\r\nserver {\r\n\tlisten 80;\r\n    server_name localhost;\r\n\r\n\tlocation / {\r\n\t\troot /var/www/html;\r\n\t\tindex index.html index.htm index.nginx-debian.html;\r\n\t}\r\n}\r\ninclude\t<someconfig>\r\n\r\nnginx -s reload\r\n```\r\n\r\n### 路径映射\r\n\r\n```nginx\r\n# = 匹配\r\nlocation = / {\r\n    # 精确匹配，不能带任何字符串\r\n}\r\n# 通用匹配\r\nlocation /xx {\r\n\t# 匹配所有/xx/的路径\r\n}\r\n# 正则匹配\r\nlocation ~/xx {\r\n    # 匹配所有以/xx开头的路径\r\n}\r\nlocation ~* \\. (git|jpg|png)$ {\r\n    # 匹配大多数图片格式\r\n}\r\n```\r\n\r\n## 实例\r\n\r\n### 反向代理\r\n\r\n```nginx\r\nlocation /test {\r\n\t# 反向代理\r\n\tproxy_pass http://group1/;\r\n}\r\n```\r\n\r\n### 文件服务器\r\n\r\n```nginx\r\nlocation /app {\r\n    # 遍历目录\r\n    autoindex on;\r\n    # 文件大小显示\r\n    autoindex_exact_size off;\r\n    # 显示服务器时间\r\n    autoindex_localtime on;\r\n    # 中文文件夹转码\r\n    charset utf-8;\r\n}\r\n\r\n```\r\n\r\n### 负载均衡\r\n\r\n> 轮询\r\n>\r\n> 权重\r\n>\r\n> iphash\r\n\r\n```nginx\r\n# 负载均衡 权重\r\nupstream group1{\r\n   \tserver 192.168.0.1:80 weight=2;\r\n    server 192.168.0.1:8080 weight=1;\r\n}\r\n\r\nserver{\r\n    location /test/ {\r\n        # 随机重定向到两个网页\r\n\t\tproxy_pass http://group1/;\r\n  }\r\n}\r\n```\r\n\r\n"}}]);